module RefModule(
    input clk,
    input rst,
    input [3:0] in_signal,
    output reg [1:0] out_signal
);

reg [1:0] unused_count;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        unused_count <= 2'b00;
        out_signal <= 2'b00;
    end else begin
        unused_count <= unused_count + 1;
        if (unused_count == 2'b01) begin
            out_signal <= in_signal[3:2]; // take the two MSBs of the input
        end
    end
end

endmodule
